#include<bits/stdc++.h>
#define LL long long
#define UInt unsigned int
#define ULL unsigned long long
#define LD long double
#define pii pair<int,int>
#define pLL pair<LL,LL>
#define pDD pair<LD,LD>
#define fr first
#define se second
#define pb push_back
#define isr insert
using namespace std;
const int N = 5e5+5;
const LL INF = 0x3f3f3f3f3f3f;
struct line{LL u,v,w;}ln[N];
LL n,m,nod,ned,l,r;
LL fa[N],Ans,wadd,cnt,bian,bqh;
LL read(){
    LL su=0,pp=1;char ch=getchar();
    while(ch<'0'||ch>'9'){if(ch=='-')pp=-1;ch=getchar();}
    while(ch>='0'&&ch<='9'){su=su*10+ch-'0';ch=getchar();}
    return su*pp;
}
bool cmp(line l1,line l2){return l1.w<l2.w;}
int FF(int u){return (fa[u]==u?u:fa[u]=FF(fa[u]));}
void Merge(int u,int v){u=FF(u),v=FF(v),fa[v]=u;return;}
void Kruskal_sol_MST(){
    sort(ln+1,ln+m+1,cmp);
    for(int i=1;i<=n;i++)fa[i]=i;
    cnt=0,bqh=0,bian=0;
    for(int i=1;i<=m;i++){
        auto [u,v,w]=ln[i];
        if(FF(u)==FF(v))continue;
        Merge(u,v),bian++;
        cnt+=(u==nod),bqh+=w;
    }return;
}
bool check(LL add){
    for(int i=1;i<=m;i++)
        if(ln[i].u==nod)ln[i].w+=add;
    Kruskal_sol_MST();
    for(int i=1;i<=m;i++)
        if(ln[i].u==nod)ln[i].w-=add;
    return (cnt>=ned);
}
int main(){
    n=read(),m=read();
    nod=read(),ned=read();
    for(int i=1;i<=m;i++){
        ln[i].u=read(),ln[i].v=read(),ln[i].w=read();
        if(ln[i].v==nod)swap(ln[i].u,ln[i].v);
    }check(0);if(bian!=n-1){cout<<"Impossible\n";return 0;}
    check(INF);if(cnt>ned){cout<<"Impossible\n";return 0;}
    check(-INF);if(cnt<ned){cout<<"Impossible\n";return 0;}
    l=-30000,r=30000,wadd=0;
    while(l<=r){
        int mid=(l+r)/2;
        if(check(mid))wadd=mid,l=mid+1;
        else r=mid-1;
    }check(wadd);cout<<bqh-wadd*ned<<"\n";
    return 0;
}
